import{_ as e,o,c as r,a2 as i}from"./chunks/framework.y1bVONfd.js";const p=JSON.parse('{"title":"Desensitization","description":"Privacy protection through automatic PII detection and masking","frontmatter":{"title":"Desensitization","description":"Privacy protection through automatic PII detection and masking"},"headers":[],"relativePath":"guide/desensitization.md","filePath":"guide/desensitization.md"}'),a={name:"guide/desensitization.md"};function d(s,t,n,l,c,h){return o(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="desensitization" tabindex="-1">Desensitization <a class="header-anchor" href="#desensitization" aria-label="Permalink to &quot;Desensitization&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>WebRouter&#39;s desensitization engine automatically detects and masks personally identifiable information (PII) in API requests before they reach upstream providers. The original data is restored in the response, so the upstream never sees sensitive information.</p><h2 id="built-in-rules" tabindex="-1">Built-in Rules <a class="header-anchor" href="#built-in-rules" aria-label="Permalink to &quot;Built-in Rules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rule</th><th>Category</th><th>Detection Method</th></tr></thead><tbody><tr><td>Phone Numbers</td><td><code>PHONE</code></td><td>Regex: Chinese mobile numbers</td></tr><tr><td>Names</td><td><code>NAME</code></td><td>Regex: Chinese name patterns</td></tr><tr><td>Addresses</td><td><code>ADDRESS</code></td><td>Regex: Address keywords</td></tr><tr><td>ID Cards</td><td><code>IDCARD</code></td><td>Pattern matching</td></tr><tr><td>Emails</td><td><code>EMAIL</code></td><td>Regex</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Before forwarding</strong> — wr-proxy scans the request body for PII patterns</li><li><strong>Masking</strong> — matched content is replaced with placeholders (<code>[PHONE_1]</code>, <code>[NAME_2]</code>, etc.)</li><li><strong>Forward</strong> — the masked request is sent to the upstream provider</li><li><strong>Response</strong> — the provider responds normally</li><li><strong>Restore</strong> — wr-proxy restores the original values in the response before sending to the client</li></ol><h2 id="custom-rules" tabindex="-1">Custom Rules <a class="header-anchor" href="#custom-rules" aria-label="Permalink to &quot;Custom Rules&quot;">​</a></h2><p>You can add custom desensitization rules:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Name</td><td>Rule identifier</td></tr><tr><td>Type</td><td><code>regex</code> (currently supported)</td></tr><tr><td>Pattern</td><td>Regular expression</td></tr><tr><td>Category</td><td>PHONE, NAME, ADDRESS, EMAIL, CUSTOM</td></tr><tr><td>Level</td><td><code>standard</code> or <code>strict</code></td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Desensitization is enabled per-token. When creating or editing a token, toggle the <strong>Desensitization</strong> switch to enable PII stripping for that token&#39;s requests.</p>',12)])])}const g=e(a,[["render",d]]);export{p as __pageData,g as default};
